# File: bayesquad/_cache.py
"""Basic caching functionality."""
from functools import wraps

_cache = {}


def last_value_cache(func):
    """Cache the result of most recent invocation of this method.

    This decorator may be applied to a method which takes one argument (excluding `self`). If the method is called
    consecutively with the same argument, the method will immediately return the previous result rather than computing
    the result again. Note that by "the same argument" we mean the same object - two different but equal objects will
    not be regarded as the same by this decorator.

    The cache is not shared between different instances of the same class.
    """
    @wraps(func)
    def transformed_function(self, x):
        cache_key = "{}_{}".format(id(self), id(func))

        if cache_key not in _cache or x is not _cache[cache_key][0]:
            ret = func(self, x)

            _cache[cache_key] = [x, ret]

            return ret
        else:
            return _cache[cache_key][1]

    return transformed_function


def clear_last_value_caches(obj):
    """Clear the :func:`~last_value_cache` of every method on the given object."""
    obj_id = str(id(obj))

    keys_to_delete = []

    for key in _cache:
        if key.startswith(obj_id):
            keys_to_delete.append(key)

    for key in keys_to_delete:
        del _cache[key]

# File: bayesquad/_decorators.py
"""Decorators to modify function behaviour."""
from functools import wraps

import numpy as np
from numpy import ndarray


def flexible_array_dimensions(func):
    """Modifies a function so it can accept either 1D or 2D arrays, returning arrays of consistent dimension."""
    @wraps(func)
    def transformed_function(*args, **kwargs):
        new_args = tuple(np.atleast_2d(arg) if isinstance(arg, ndarray)
                         else arg
                         for arg in args)

        values = func(*new_args, **kwargs)

        if all([arg is new_arg for arg, new_arg in zip(args, new_args)]):
            return values

        if isinstance(values, tuple):
            return tuple(np.squeeze(value, axis=0) if isinstance(value, ndarray) and np.size(value, 0) == 1
                         else value
                         for value in values)
        elif isinstance(values, ndarray) and np.size(values, 0) == 1:
            return np.squeeze(values, axis=0)
        else:
            return values

    return transformed_function

# File: bayesquad/_util.py
"""Miscellaneous utility functions"""

import numpy as np
from numpy import ndarray


def validate_dimensions(x: ndarray, expected_dimensionality: int):
    """Checks that `x` represents data of dimensionality `expected_dimensions`."""
    array_dimensions = np.ndim(x)

    if array_dimensions != 2:
        raise ValueError("Expected a 2-dimensional array, but got a {}-dimensional array.".format(array_dimensions))

    actual_dimensionality = np.size(x, 1)

    if actual_dimensionality != expected_dimensionality:
        raise ValueError("Expected data in {} dimensions, but got data in {} dimensions."
                         .format(expected_dimensionality, actual_dimensionality))

# File: bayesquad/_maths_helpers.py
"""A home for mathematical operations which are used multiple times in this package."""

from numpy import ndarray, newaxis


def jacobian_of_f_squared_times_g(*,
        f: ndarray, f_jacobian: ndarray,
        g: ndarray, g_jacobian: ndarray) -> ndarray:
    """Given f, g and their Jacobians, returns the Jacobian of f^2 * g."""
    assert f.ndim == g.ndim == 1, "Function data must be a 1-dimensional array"
    assert f_jacobian.ndim == g_jacobian.ndim == 2, "Function Jacobian data must be a 2-dimensional array"

    f, g = f[:, newaxis], g[:, newaxis]
    jacobian = 2 * f * g * f_jacobian + g_jacobian * f ** 2
    return jacobian


def hessian_of_f_squared_times_g(*,
        f: ndarray, f_jacobian: ndarray, f_hessian: ndarray,
        g: ndarray, g_jacobian: ndarray, g_hessian: ndarray) -> ndarray:
    """Given f, g and their Jacobian/Hessian, returns the Hessian of f^2 * g."""
    assert f.ndim == g.ndim == 1, "Function data must be a 1-dimensional array"
    assert f_jacobian.ndim == g_jacobian.ndim == 2, "Function Jacobian data must be a 2-dimensional array"
    assert f_hessian.ndim == g_hessian.ndim == 3, "Function Hessian data must be a 3-dimensional array"

    f, g = f[:, newaxis, newaxis], g[:, newaxis, newaxis]
    f_jacobian_dxj, g_jacobian_dxj = f_jacobian[:, :, newaxis], g_jacobian[:, :, newaxis]
    f_jacobian_dxk, g_jacobian_dxk = f_jacobian[:, newaxis, :], g_jacobian[:, newaxis, :]

    hessian = \
        2 * f * (
                f_hessian * g +
                g_jacobian_dxj * f_jacobian_dxk +
                f_jacobian_dxj * g_jacobian_dxk
        ) + 2 * g * f_jacobian_dxj * f_jacobian_dxk \
        + g_hessian * f ** 2

    return hessian

