"""Functions for computing the gradients of Gaussian Process kernels."""

import numpy as np

from GPy.kern.src.kern import Kern
from GPy.kern.src.rbf import RBF
from GPy.kern.src.stationary import Stationary
from numpy import ndarray, newaxis


def jacobian(kernel: Kern, variable_points: ndarray, fixed_points: ndarray) -> ndarray:
    """Return the Jacobian of an RBF kernel evaluated at all pairs from two sets of points."""
    if isinstance(kernel, RBF):
        lengthscale = kernel.lengthscale.values[0]
        k = kernel.K(variable_points, fixed_points)
        differences = variable_points[:, newaxis, :] - fixed_points[newaxis, :, :]
        return -k[:, :, newaxis] * differences / (lengthscale ** 2)
    else:
        raise NotImplementedError


def hessian(kernel: Kern, variable_points: ndarray, fixed_points: ndarray) -> ndarray:
    """Return the Hessian of an RBF kernel evaluated at all pairs from two sets of points."""
    if isinstance(kernel, RBF):
        lengthscale = kernel.lengthscale.values[0]
        k = kernel.K(variable_points, fixed_points)

        _, num_dimensions = variable_points.shape
        differences = variable_points[:, newaxis, :] - fixed_points[newaxis, :, :]
        outer_products_of_differences = np.einsum('ijk,ijl->ijkl', differences, differences, optimize=True)
        transformed_outer_products = (outer_products_of_differences / lengthscale ** 2) - np.eye(num_dimensions)
        product = np.einsum('ij,ijkl->ijkl', k, transformed_outer_products, optimize=True)
        return product / (lengthscale ** 2)
    else:
        raise NotImplementedError


def diagonal_hessian(kernel: Kern, x: ndarray) -> ndarray:
    """Return the Hessian of K(x,x) for stationary kernels (zero for RBF)."""
    if isinstance(kernel, Stationary):
        num_points, num_dimensions = x.shape
        return np.zeros((num_points, num_dimensions, num_dimensions))
    else:
        raise NotImplementedError

# File: bayesquad/priors.py
"""Classes representing probability distributions, intended to be integrated against a likelihood."""

from abc import ABC, abstractmethod
from typing import Tuple

import numpy as np
import scipy.stats
from numpy import ndarray, newaxis

from ._util import validate_dimensions


class Prior(ABC):
    """A prior, providing methods for sampling, and for pointwise evaluation of the pdf and its derivatives."""

    @abstractmethod
    def gradient(self, x: ndarray) -> Tuple[ndarray, ndarray]:
        pass

    @abstractmethod
    def sample(self, num_points: int = 1) -> ndarray:
        pass

    @abstractmethod
    def logpdf(self, x: ndarray) -> ndarray:
        pass

    @abstractmethod
    def __call__(self, x: ndarray) -> ndarray:
        pass


class Gaussian(Prior):
    """A multivariate Gaussian prior."""
    def __init__(self, mean: ndarray, covariance: ndarray):
        self.mean = mean
        self.covariance = covariance
        self.precision = np.linalg.inv(covariance)

        self._dimensions = np.size(mean)
        self._multivariate_normal = scipy.stats.multivariate_normal(mean=mean, cov=covariance)

    def sample(self, num_points: int = 1) -> ndarray:
        sample = self._multivariate_normal.rvs(size=num_points)
        if self._dimensions == 1:
            sample = sample[:, newaxis]
        return sample

    def gradient(self, x: ndarray) -> Tuple[ndarray, ndarray]:
        validate_dimensions(x, self._dimensions)
        cov_inv_x = np.einsum('jk,ik->ij', self.precision, x - self.mean, optimize=True)
        jacobian = -self(x)[:, newaxis] * cov_inv_x
        outer_products = cov_inv_x[:, newaxis, :] * cov_inv_x[:, :, newaxis]
        hessian = self(x)[:, newaxis, newaxis] * (outer_products - self.precision[newaxis, :, :])
        return jacobian, hessian

    def logpdf(self, x: ndarray) -> ndarray:
        validate_dimensions(x, self._dimensions)
        return np.atleast_1d(self._multivariate_normal.logpdf(x))

    def __call__(self, x: ndarray) -> ndarray:
        validate_dimensions(x, self._dimensions)
        return np.atleast_1d(self._multivariate_normal.pdf(x))

